import React from 'react';
import { TrendingUp, Users, Star, BookOpen } from 'lucide-react';
import AnimatedCounter from './AnimatedCounter';

const QuickStats = ({ courses, enrolledCourses = [] }) => {
  const totalCourses = courses.length;
  const totalEnrolled = enrolledCourses.length;
  const avgRating = courses.length > 0 
    ? (courses.reduce((sum, course) => sum + parseFloat(course.rating), 0) / courses.length).toFixed(1)
    : '0.0';
  const totalStudents = courses.reduce((sum, course) => sum + course.enrolled, 0);

  const stats = [
    {
      icon: BookOpen,
      label: 'Available Courses',
      value: totalCourses,
      color: 'blue'
    },
    {
      icon: TrendingUp,
      label: 'Enrolled Courses',
      value: totalEnrolled,
      color: 'green'
    },
    {
      icon: Star,
      label: 'Average Rating',
      value: parseFloat(avgRating),
      color: 'yellow',
      suffix: '/5'
    },
    {
      icon: Users,
      label: 'Total Students',
      value: totalStudents,
      color: 'purple',
      format: 'number'
    }
  ];

  const getColorClasses = (color) => {
    const colors = {
      blue: 'bg-blue-50 text-blue-600 border-blue-200',
      green: 'bg-green-50 text-green-600 border-green-200',
      yellow: 'bg-yellow-50 text-yellow-600 border-yellow-200',
      purple: 'bg-purple-50 text-purple-600 border-purple-200'
    };
    return colors[color] || colors.blue;
  };

  return (
    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
      {stats.map((stat, index) => {
        const Icon = stat.icon;
        return (
          <div
            key={index}
            className={`p-4 rounded-xl border-2 ${getColorClasses(stat.color)} transition-all duration-200 hover:scale-105`}
          >
            <div className="flex items-center justify-between mb-2">
              <Icon className="w-5 h-5" />
              <div className="text-right">
                <div className="text-lg font-bold">
                  <AnimatedCounter 
                    end={stat.value} 
                    suffix={stat.suffix || ''} 
                    duration={1500}
                  />
                </div>
              </div>
            </div>
            <p className="text-xs font-medium opacity-75">{stat.label}</p>
          </div>
        );
      })}
    </div>
  );
};

export default QuickStats;
